module radix2_div (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output wire [15:0] result
);

reg [7:0] dividend_reg;
reg [7:0] divisor_reg;
reg [15:0] result_reg;
reg [3:0] cnt;
reg [3:0] start_cnt;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        dividend_reg <= 8'b0;
        divisor_reg <= 8'b0;
        result_reg <= 16'b0;
        cnt <= 4'b0;
        start_cnt <= 4'b0;
        res_valid <= 1'b0;
    end else if (opn_valid && !res_valid) begin
        dividend_reg <= dividend;
        divisor_reg <= divisor;
        result_reg <= {dividend, 8'b0};
        cnt <= 4'b1;
        start_cnt <= 4'b1;
        res_valid <= 1'b1;
    end else if (start_cnt) begin
        if (cnt == 4'd8) begin
            cnt <= 4'b0;
            start_cnt <= 4'b0;
            result_reg <= {result_reg[7:0], result_reg[15:8]};
        end else begin
            result_reg <= {result_reg[7:0] - divisor_reg, result_reg[15:8]};
            cnt <= cnt + 1;
        end
    end
end

assign result = result_reg;

endmodule
